mapper.select:
SELECT c.*, u.nickname as user_name, u.avatar as user_avatar, p.name as product_name, p.main_image as product_image, ru.nickname as reply_user_name FROM product_comment c LEFT JOIN sys_user u ON c.user_id = u.id LEFT JOIN product p ON c.product_id = p.id LEFT JOIN sys_user ru ON c.reply_user_id = ru.id
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
AND c.product_id = #{productId}
AND c.rating = #{rating}
AND c.reply_content IS NOT NULL AND c.reply_content != ''
AND (c.reply_content IS NULL OR c.reply_content = '')
AND c.status = #{status}
ORDER BY c.create_time DESC
